@@ -364,6 +364,23 @@ CLI11_INLINE Option *App::_add_flag_internal(...) {
+    if(!negation_prefix_.empty()) {
+        auto lnames_copy = opt->lnames_;
+        for(const auto &lname : lnames_copy) {
+            if(lname.substr(0, negation_prefix_.size()) == negation_prefix_) continue;
+            std::string neg_name = negation_prefix_ + lname;
+            if(detail::find_member(neg_name, opt->lnames_, ...) < 0) {
+                opt->lnames_.push_back(neg_name);
+                opt->fnames_.push_back(neg_name);
+                opt->default_flag_values_.emplace_back(neg_name, "false");
+            }
+        }
